// Clean Common Props
// ==============================

export const cleanCommonProps = props => {
  //className
  const {
    className,
    // not listed in commonProps documentation, needs to be removed to allow Emotion to generate classNames
    clearValue,
    cx,
    xcss,
    getStyles,
    getClassNames,
    getValue,
    hasValue,
    isMulti,
    isRtl,
    options,
    // not listed in commonProps documentation
    selectOption,
    selectProps,
    setValue,
    ...innerProps
  } = props;
  return {
    ...innerProps
  };
};